#!/usr/bin/env python3
import base64, os

PROJECT = os.path.expanduser("~/Desktop/dream-abroad")

files = {
    "backend/routers/transactions.py": "",
    "frontend/src/pages/TransactionsIn.tsx": "",
}

for rel_path, b64 in files.items():
    full = os.path.join(PROJECT, rel_path)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, "w") as f:
        f.write(base64.b64decode(b64).decode())
    print(f"Updated: {rel_path}")

api_path = os.path.join(PROJECT, "frontend/src/services/api.ts")
with open(api_path, "r") as f:
    c = f.read()
if "localhost:8000" in c:
    c = c.replace("http://localhost:8000", "")
    with open(api_path, "w") as f:
        f.write(c)
    print("Fixed api.ts baseURL")

print("Done!")
